    "\n    query getLoansTransactionsHistory($marketTokenAddress: String, $userAddress: String = \"\", $vaultAddress: String = \"\", $typeFilter: [smallint] = []) {\n      lending_controller(where: {mock_time: {_eq: false}}) {\n        history_data(where: {, loan_token: {token: {token_address: {_eq: $marketTokenAddress}}}, , }, distinct_on: timestamp, order_by: {timestamp: desc}) {\n          type\n          amount\n          timestamp\n          loan_token {\n            loan_token_name\n            token {\n              token_address\n            }\n          }\n          collateral_token {\n            token {\n              token_address\n              mvk_tokens {\n                address\n              }\n            }\n          }\n          operation_hash\n          sender {\n            address\n          }\n          vault {\n            vault {\n              address\n            }\n          }\n        }\n      }\n    }\n": types.GetLoansTransactionsHistoryDocument,
    "\n    query getLoansMarketsQuery($marketTokenAddress: String = \"\") {\n\t\t\tallMarketsAddresses: lending_controller(where: {mock_time: {_eq: false}}) {\n\t\t\t\tloan_tokens {\n\t\t\t\t\ttoken {\n\t\t\t\t\t\ttoken_address\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t}\n\n      lending_controller(where: {mock_time: {_eq: false}}) {\n\t\t\t\tcollateral_ratio\n\t\t\t\tinterest_treasury_share\n\t\t\t\tinterest_rate_decimals\n\t\t\t\tdecimals\n\n\t\t\t\tloan_tokens(where: {}) {\n\t\t\t\t\ttoken {\n\t\t\t\t\t\ttoken_address\n\t\t\t\t\t}\n\n\t\t\t\t\tloan_token_name\n\t\t\t\t\tid\n\t\t\t\t\tutilisation_rate\n\t\t\t\t\ttotal_borrowed\n\t\t\t\t\ttoken_pool_total\n\t\t\t\t\ttotal_remaining\n\t\t\t\t\treserve_ratio\n\t\t\t\t\tcurrent_interest_rate\n\n\t\t\t\t\t# market lending item address, and amount of suppliers\n\t\t\t\t\tm_token {\n\t\t\t\t\t\taddress\n\t\t\t\t\t\taccounts_aggregate(where: {balance: {_gte: 0}}) {\n\t\t\t\t\t\t\taggregate {\n\t\t\t\t\t\t\t\tcount\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t}\n\t\t\t\t\t}\n\n\t\t\t\t\t# number of borrowers\n\t\t\t\t\tvaults_aggregate(where: {loan_outstanding_total: {_neq: \"0\"}}) {\n\t\t\t\t\t\taggregate {\n\t\t\t\t\t\t\tcount(distinct: true, columns: owner_id)\n\t\t\t\t\t\t}\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t}\n    }\n": types.GetLoansMarketsQueryDocument,
